$ErrorActionPreference = 'Stop'
$ProgressPreference = 'SilentlyContinue'
$baseId = [Environment]::GetEnvironmentVariable('DCOIR_AIRTABLE_BASE_ID','Machine')
$token = [Environment]::GetEnvironmentVariable('DCOIR_AIRTABLE_TOKEN','Machine')
$downloads = [Environment]::GetEnvironmentVariable('DCOIR_DOWNLOADS_DIR','Machine')
if ([string]::IsNullOrWhiteSpace($baseId)) { throw 'Missing DCOIR_AIRTABLE_BASE_ID' }
if ([string]::IsNullOrWhiteSpace($token)) { throw 'Missing DCOIR_AIRTABLE_TOKEN' }
if ([string]::IsNullOrWhiteSpace($downloads)) { throw 'Missing DCOIR_DOWNLOADS_DIR' }
$headers = @{ Authorization = "Bearer $token" }
$checkpointRecordId = 'recbTUgYn2CAJH1rT'
$checkpointKey = 'CHK-DCOIR-AIRTABLE-CLEANUP-CLOSEOUT-20260506-CHATGPT-EXEC-TOOLPATH-WBS09'
$targets = @(
  [ordered]@{ key='governance_control_plane'; name='Governance Control Plane'; id='tblDfSl29psxRnes1'; match='CONTROL-STARTUP-AIRTABLE-FIRST' },
  [ordered]@{ key='queue_control'; name='Queue Control'; id='tblf13aCslg6rJBah'; match='' },
  [ordered]@{ key='plans'; name='Plans'; id='tblBcp5FyMIfOm7Xe'; match='PLAN-AIRTABLE-CLEANUP-RESTRUCTURE|active|current|cleanup|WBS08|WBS09' },
  [ordered]@{ key='operator_preferences'; name='Operator Preferences'; id='tblnxZ3eLPT3W38wl'; match='' },
  [ordered]@{ key='session_checkpoints'; name='Session Checkpoints'; id='tblTe75HKZOJaPDGn'; match='CHK-DCOIR-AIRTABLE-CLEANUP-CLOSEOUT-20260506-CHATGPT-EXEC-TOOLPATH-WBS09|recbTUgYn2CAJH1rT|PLAN-AIRTABLE-CLEANUP-RESTRUCTURE|WBS08|WBS09' },
  [ordered]@{ key='cleanup_wbs'; name='DCOIR Cleanup WBS'; id='tblRxTmpW0VunQlUK'; match='WBS08|WBS09|PLAN-AIRTABLE-CLEANUP-RESTRUCTURE|active|current|planned|complete' }
)
function Get-ErrorText {
  param($Err)
  try {
    $resp = $Err.Exception.Response
    if ($null -ne $resp) {
      $stream = $resp.GetResponseStream()
      if ($null -ne $stream) {
        $reader = New-Object System.IO.StreamReader($stream)
        $body = $reader.ReadToEnd()
        if (-not [string]::IsNullOrWhiteSpace($body)) { return $body }
      }
    }
  } catch { }
  return $Err.Exception.Message
}
function Redact-Value {
  param($Value, [string]$FieldName = '')
  if ($null -eq $Value) { return $null }
  if ($FieldName -match '(?i)(token|secret|password|credential|api[_ -]?key)') { return '[REDACTED_FIELD]' }
  if ($Value -is [string]) {
    $v = $Value
    if ($v -match '(?i)(pat_|ghp_|gho_|ghu_|ghs_|github_pat_|sk-[A-Za-z0-9]|key=|token=|Bearer\s+)') { return '[REDACTED_VALUE]' }
    if ($v.Length -gt 4000) { return $v.Substring(0,4000) + "`n[TRUNCATED]" }
    return $v
  }
  if ($Value -is [System.Array]) { return @($Value | ForEach-Object { Redact-Value -Value $_ -FieldName $FieldName }) }
  return $Value
}
function Convert-RecordSafe {
  param($Record)
  $fields = [ordered]@{}
  if ($Record.PSObject.Properties.Name -contains 'fields') {
    foreach ($p in $Record.fields.PSObject.Properties) {
      $fields[$p.Name] = Redact-Value -Value $p.Value -FieldName $p.Name
    }
  }
  return [ordered]@{ id=$Record.id; createdTime=$Record.createdTime; fields=$fields }
}
function Get-RecordsNoQueryNoThrow {
  param([string]$TableRef)
  try {
    $encodedTable = [uri]::EscapeDataString($TableRef)
    $uri = "https://api.airtable.com/v0/$baseId/$encodedTable"
    $all = New-Object System.Collections.Generic.List[object]
    do {
      $resp = Invoke-RestMethod -Method Get -Uri $uri -Headers $headers
      foreach ($record in @($resp.records)) { $all.Add($record) }
      if ($resp.offset) {
        $encodedOffset = [uri]::EscapeDataString([string]$resp.offset)
        $uri = "https://api.airtable.com/v0/$baseId/$encodedTable?offset=$encodedOffset"
      } else { $uri = $null }
    } while ($uri)
    return [ordered]@{ ok=$true; records=@($all); error=$null }
  } catch {
    return [ordered]@{ ok=$false; records=@(); error=(Get-ErrorText $_) }
  }
}
function Get-RecordNoThrow {
  param([string]$TableRef, [string]$RecordId)
  try {
    $encodedTable = [uri]::EscapeDataString($TableRef)
    $encodedRecord = [uri]::EscapeDataString($RecordId)
    $uri = "https://api.airtable.com/v0/$baseId/$encodedTable/$encodedRecord"
    $resp = Invoke-RestMethod -Method Get -Uri $uri -Headers $headers
    return [ordered]@{ ok=$true; record=$resp; error=$null }
  } catch {
    return [ordered]@{ ok=$false; record=$null; error=(Get-ErrorText $_) }
  }
}
function Select-Matched {
  param($Records, [string]$Match)
  $safe = @($Records | ForEach-Object { Convert-RecordSafe -Record $_ })
  if ([string]::IsNullOrWhiteSpace($Match)) { return $safe }
  $rx = [regex]::new($Match, [System.Text.RegularExpressions.RegexOptions]::IgnoreCase)
  return @($safe | Where-Object { $rx.IsMatch(($_ | ConvertTo-Json -Depth 20 -Compress)) })
}
$summary = [ordered]@{
  generated_utc = (Get-Date).ToUniversalTime().ToString('yyyy-MM-ddTHH:mm:ssZ')
  base_id = $baseId
  lane = 'chatgpt-exec Airtable records API only; plain table list without pageSize/maxRecords'
  checkpoint_key = $checkpointKey
  checkpoint_record_id = $checkpointRecordId
  exact_checkpoint = [ordered]@{}
  tables = [ordered]@{}
}
$cp = Get-RecordNoThrow -TableRef 'tblTe75HKZOJaPDGn' -RecordId $checkpointRecordId
$summary.exact_checkpoint = [ordered]@{ ok=$cp.ok; error=$cp.error; record=$(if ($cp.ok) { Convert-RecordSafe -Record $cp.record } else { $null }) }
$summary.exact_session_checkpoint_verified = [bool]$cp.ok
foreach ($target in $targets) {
  $byId = Get-RecordsNoQueryNoThrow -TableRef $target.id
  $byName = $null
  $chosen = $null
  $chosenRef = 'none'
  if ($byId.ok) { $chosen=$byId; $chosenRef='table_id' }
  else {
    $byName = Get-RecordsNoQueryNoThrow -TableRef $target.name
    if ($byName.ok) { $chosen=$byName; $chosenRef='table_name' } else { $chosen=$byName }
  }
  $records = if ($null -ne $chosen -and $chosen.ok) { @($chosen.records) } else { @() }
  $matched = Select-Matched -Records $records -Match $target.match
  $summary.tables[$target.key] = [ordered]@{
    table_name=$target.name
    table_id=$target.id
    chosen_ref=$chosenRef
    table_id_ok=$byId.ok
    table_id_error=$byId.error
    table_name_ok=$(if ($null -eq $byName) { $null } else { $byName.ok })
    table_name_error=$(if ($null -eq $byName) { $null } else { $byName.error })
    fetched_count=@($records).Count
    matched_count=@($matched).Count
    records=$matched
  }
}
$outDir = Join-Path $downloads 'reanchor_records_api_20260506_004'
New-Item -ItemType Directory -Force -Path $outDir | Out-Null
$jsonPath = Join-Path $outDir 'reanchor_records_api_readback.json'
$mdPath = Join-Path $outDir 'reanchor_records_api_summary.md'
$summary | ConvertTo-Json -Depth 30 | Set-Content -LiteralPath $jsonPath -Encoding UTF8
$lines = New-Object System.Collections.Generic.List[string]
$lines.Add('# DCOIR re-anchor records API readback 004')
$lines.Add('')
$lines.Add("- generated_utc: $($summary.generated_utc)")
$lines.Add("- base_id: $baseId")
$lines.Add("- lane: records API only; plain table list without pageSize/maxRecords")
$lines.Add("- exact checkpoint verified: $($summary.exact_session_checkpoint_verified)")
$lines.Add('')
$lines.Add('| key | table | chosen_ref | fetched | matched | id_ok | name_ok |')
$lines.Add('|---|---|---|---:|---:|---:|---:|')
foreach ($key in $summary.tables.Keys) {
  $t = $summary.tables[$key]
  $lines.Add("| $key | $($t.table_name) | $($t.chosen_ref) | $($t.fetched_count) | $($t.matched_count) | $($t.table_id_ok) | $($t.table_name_ok) |")
}
$lines.Add('')
$lines.Add('## Active/resume matched records')
foreach ($key in $summary.tables.Keys) {
  $t = $summary.tables[$key]
  $lines.Add('')
  $lines.Add("### $key")
  foreach ($r in @($t.records)) {
    $name = ''
    foreach ($candidate in @('Name','Title','Key','control_key','queue_key','plan_key','checkpoint_key','wbs_key','preference_key','Status','status','State','state')) {
      if ($r.fields.Contains($candidate)) { $name += "$candidate=$($r.fields[$candidate]); " }
    }
    $lines.Add("- $($r.id): $name")
  }
}
$lines | Set-Content -LiteralPath $mdPath -Encoding UTF8
Write-Output "DCOIR corrected re-anchor records API readback complete."
Write-Output "Summary markdown: $mdPath"
Write-Output "JSON readback: $jsonPath"
Write-Output ("Exact checkpoint verified: " + $summary.exact_session_checkpoint_verified)
foreach ($key in $summary.tables.Keys) {
  $t = $summary.tables[$key]
  Write-Output ("{0}: chosen={1}; fetched={2}; matched={3}; table_id={4}" -f $key,$t.chosen_ref,$t.fetched_count,$t.matched_count,$t.table_id)
}
